import React, { useState } from 'react';

function Profile({ user, onUpdate, onBack }) {
  const [name, setName] = useState(user?.name || '');
  const [age, setAge] = useState(user?.age || '');
  const [city, setCity] = useState(user?.city || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [profilePic, setProfilePic] = useState(user?.profilePic || null);

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) { alert('❌ Image trop grande (max 2 Mo)'); return; }
      const reader = new FileReader();
      reader.onload = (e) => setProfilePic(e.target.result);
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!name || !age || !city) { alert('❌ Veuillez remplir tous les champs'); return; }
    const updatedUser = { ...user, name, age: parseInt(age), city, bio, profilePic };
    alert('✅ Profil mis à jour!');
    if (onUpdate) onUpdate(updatedUser);
    onBack();
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <button style={styles.backBtn} onClick={onBack}>← Retour</button>
        <h1 style={styles.title}>👤 Mon Profil</h1>
        <div style={styles.imageContainer}>
          {profilePic ? <img src={profilePic} alt="Profile" style={styles.profileImage} /> : <div style={styles.profilePlaceholder}><span style={styles.emoji}>📸</span></div>}
          <label style={styles.uploadBtn}>📷 Changer la photo<input type="file" accept="image/*" onChange={handleImageUpload} style={styles.fileInput} /></label>
          <p style={styles.hint}>Format: JPG, PNG (max 2 Mo)</p>
        </div>
        <input type="text" placeholder="👤 Nom complet" value={name} onChange={(e) => setName(e.target.value)} style={styles.input} />
        <input type="number" placeholder="🎂 Âge" value={age} onChange={(e) => setAge(e.target.value)} style={styles.input} />
        <input type="text" placeholder="📍 Ville" value={city} onChange={(e) => setCity(e.target.value)} style={styles.input} />
        <textarea placeholder="💕 Bio" value={bio} onChange={(e) => setBio(e.target.value)} style={styles.textarea} rows="3" />
        <button style={styles.saveBtn} onClick={handleSave}>💾 Enregistrer</button>
        <div style={styles.hearts}><span style={styles.heart}>❤️</span><span style={styles.heart}>💕</span><span style={styles.heart}>❤️</span></div>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1 0%, #87CEEB 100%)', padding: '20px', fontFamily: 'Arial, sans-serif' },
  card: { backgroundColor: 'white', borderRadius: '24px', padding: '40px', width: '100%', maxWidth: '450px', boxShadow: '0 20px 60px rgba(0,0,0,0.15)', textAlign: 'center', position: 'relative' },
  backBtn: { position: 'absolute', top: '15px', left: '20px', background: 'none', border: 'none', fontSize: '1.2rem', cursor: 'pointer', color: '#888', fontWeight: 'bold' },
  title: { fontSize: '2rem', fontWeight: 'bold', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', marginBottom: '25px' },
  imageContainer: { display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: '20px' },
  profileImage: { width: '120px', height: '120px', borderRadius: '50%', objectFit: 'cover', border: '4px solid #FF69B4' },
  profilePlaceholder: { width: '120px', height: '120px', borderRadius: '50%', backgroundColor: '#f0f0f0', display: 'flex', justifyContent: 'center', alignItems: 'center', border: '4px solid #FF69B4' },
  emoji: { fontSize: '50px' },
  uploadBtn: { marginTop: '10px', padding: '10px 20px', backgroundColor: '#f0f0f0', borderRadius: '10px', cursor: 'pointer', fontSize: '0.9rem', fontWeight: 'bold', color: '#555' },
  hint: { fontSize: '0.7rem', color: '#999', marginTop: '5px' },
  fileInput: { display: 'none' },
  input: { width: '100%', padding: '14px 16px', margin: '10px 0', borderRadius: '12px', border: '2px solid #e8e8e8', fontSize: '1rem', boxSizing: 'border-box', outline: 'none' },
  textarea: { width: '100%', padding: '14px 16px', margin: '10px 0', borderRadius: '12px', border: '2px solid #e8e8e8', fontSize: '1rem', boxSizing: 'border-box', outline: 'none', resize: 'vertical', fontFamily: 'Arial, sans-serif' },
  saveBtn: { width: '100%', padding: '14px', marginTop: '20px', borderRadius: '12px', border: 'none', background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer', boxShadow: '0 4px 20px rgba(255,20,147,0.35)' },
  hearts: { marginTop: '20px', display: 'flex', justifyContent: 'center', gap: '15px' },
  heart: { fontSize: '1.5rem', animation: 'pulse 1.5s infinite' },
};

const styleSheet = document.createElement('style');
styleSheet.textContent = `@keyframes pulse { 0% { transform: scale(1); } 50% { transform: scale(1.3); } 100% { transform: scale(1); } }`;
document.head.appendChild(styleSheet);

export default Profile;
